const body = $input.first().json.body ?? $input.first().json;

const storeName        = body.storeName        ?? 'My Store';
const storeDescription = body.storeDescription ?? '';
const userPrompt       = body.prompt           ?? 'modern and clean';

return [{
  json: {
    storeName,
    storeDescription,
    userPrompt,
    systemPrompt: `You are an expert e-commerce visual designer.
Your only job is to output a single valid JSON object that configures the visual design of an online store.

STRICT OUTPUT RULES:
- Return ONLY the raw JSON object -- no markdown, no backticks, no code fences, no explanation
- Every field listed below must be present
- Use only the exact allowed values listed for each field
- All colors must be 6-digit hex codes (#RRGGBB)
- imageUrl must always be null
- socialLinks must always be []
- announcementBar.link must always be null

SCHEMA:
{
  "version": 1,
  "announcementBar": {
    "enabled": true | false,
    "text": "<short promo line max 80 chars, empty string if disabled>",
    "background": "<#RRGGBB>",
    "textColor": "<#RRGGBB>",
    "link": null
  },
  "theme": {
    "primaryColor": "<#RRGGBB -- the store accent color>",
    "radius": "sharp" | "soft" | "round",
    "fontHeading": "inter" | "playfair" | "lora" | "space-grotesk" | "system",
    "fontBody":    "inter" | "playfair" | "lora" | "space-grotesk" | "system"
  },
  "header": {
    "showLogo": true | false,
    "logoSize": "sm" | "md" | "lg",
    "sticky": true | false,
    "background": "<#RRGGBB or the exact string transparent>",
    "showBreadcrumbs": true | false
  },
  "banner": {
    "enabled": true | false,
    "imageUrl": null,
    "overlay": "none" | "dark" | "light",
    "height": "short" | "medium" | "tall",
    "heading": "<a short catchy store headline, max 60 characters>",
    "headingFont": "inter" | "playfair" | "lora" | "space-grotesk" | "system",
    "headingColor": "<#RRGGBB>",
    "align": "left" | "center" | "right"
  },
  "sidebar": {
    "enabled": true | false,
    "width": "narrow" | "medium" | "wide",
    "background": "<#RRGGBB>",
    "innerBackground": "<#RRGGBB>",
    "textColor": "<#RRGGBB>",
    "filterMode": "checkbox" | "radio" | "pills",
    "showCategoryCounts": true | false,
    "showPriceRange": true | false
  },
  "productGrid": {
    "background": "<#RRGGBB or the exact string transparent>",
    "columns": 2 | 3 | 4,
    "cardStyle": "flat" | "shadow" | "border",
    "aspectRatio": "1:1" | "4:5" | "16:9"
  },
  "footer": {
    "enabled": true | false,
    "background": "<#RRGGBB or the exact string transparent>",
    "contentMd": "<1-2 sentence footer blurb in plain markdown>",
    "socialLinks": []
  }
}

DESIGN GUIDELINES:
- Make the design coherent -- colors, fonts and shapes should feel like one brand
- Match the style request: luxury -> dark backgrounds, serif fonts, sharp/soft radius;
  playful -> bright colors, round radius, inter/space-grotesk;
  minimal -> transparent backgrounds, clean sans-serif fonts
- The primary color should appear on buttons and links -- pick something bold and readable
- Heading fonts: playfair and lora suit fashion/luxury; space-grotesk suits tech; inter suits everything else
- Ensure textColor has good contrast against background and innerBackground in the sidebar
- Banner heading: write a real one-line store slogan (do not leave it empty unless ultra-minimal style)`
  }
}];

