const raw = $input.first().json?.output
         ?? $input.first().json?.text
         ?? $input.first().json?.message?.content
         ?? '';

// Strip markdown code fences if the model added them
const cleaned = raw
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

let design;
try {
  design = JSON.parse(cleaned);
} catch (e) {
  throw new Error('LLM returned invalid JSON: ' + cleaned.slice(0, 300));
}

// Enforce hard constraints
design.version                    = 1;
design.banner.imageUrl            = null;
design.footer.socialLinks         = [];
if (design.announcementBar) design.announcementBar.link = null;

// Clamp columns
if (![2, 3, 4].includes(design.productGrid?.columns)) {
  design.productGrid.columns = 3;
}

// Validate hex colors -- fallback to safe default if invalid
const hexRe = /^#[0-9A-Fa-f]{6}$/;
const fix = (c) => hexRe.test(c) ? c : '#1E40AF';
const orTransparent = (c) => c === 'transparent' ? 'transparent' : fix(c);

if (design.announcementBar) {
  design.announcementBar.background = fix(design.announcementBar.background);
  design.announcementBar.textColor  = fix(design.announcementBar.textColor);
}
design.theme.primaryColor        = fix(design.theme.primaryColor);
design.header.background         = orTransparent(design.header.background);
design.banner.headingColor       = fix(design.banner.headingColor);
design.sidebar.background        = fix(design.sidebar.background);
design.sidebar.innerBackground   = fix(design.sidebar.innerBackground);
design.sidebar.textColor         = fix(design.sidebar.textColor);
design.productGrid.background    = orTransparent(design.productGrid.background);
design.footer.background         = orTransparent(design.footer.background);

return [{ json: design }];
